try:
    from scapy.all import rdpcap, TCP, UDP, IP, Raw, HTTP
    import re

    pcap_path = r"C:\Users\ASUS\Desktop\agent-test\agent-web\challenges\web_demo\workspace\0-2000.pcap"

    print("正在读取 PCAP 文件...")
    packets = rdpcap(pcap_path)
    print(f"总共读取 {len(packets)} 个数据包\n")

    # 统计信息
    protocols = {}
    src_ips = {}
    dst_ips = {}
    dst_ports = {}

    # 攻击特征
    suspicious_patterns = []
    http_requests = []

    for pkt in packets:
        # 协议统计
        proto = pkt.sprintf("%IP.proto%") if pkt.haslayer(IP) else "Non-IP"
        protocols[proto] = protocols.get(proto, 0) + 1

        # IP 统计
        if pkt.haslayer(IP):
            src = pkt[IP].src
            dst = pkt[IP].dst
            src_ips[src] = src_ips.get(src, 0) + 1
            dst_ips[dst] = dst_ips.get(dst, 0) + 1

        # 端口统计
        if pkt.haslayer(TCP):
            port = pkt[TCP].dport
            dst_ports[port] = dst_ports.get(port, 0) + 1
        elif pkt.haslayer(UDP):
            port = pkt[UDP].dport
            dst_ports[port] = dst_ports.get(port, 0) + 1

        # 提取 HTTP 流量和可疑内容
        if pkt.haslayer(Raw):
            payload = bytes(pkt[Raw].load)
            try:
                payload_str = payload.decode('utf-8', errors='ignore')

                # 检测 HTTP 请求
                if payload_str.startswith(('GET ', 'POST ', 'PUT ', 'DELETE ')):
                    http_requests.append(payload_str[:500])

                # 检测攻击特征
                attack_patterns = {
                    'SQL注入': [r"(\bOR\b.*=.*)", r"(UNION.*SELECT)", r"(\'.*OR.*\'.*=.*\')", r"(--)", r"(;.*DROP)", r"(\'.*\bAND\b.*\'.*=)"],
                    'XSS攻击': [r"(<script[^>]*>)", r"(javascript:)", r"(onerror\s*=)", r"(onload\s*=)"],
                    '命令注入': [r"(\|.*ls)", r"(\|.*cat)", r"(;.*whoami)", r"(\$\(.*\))"],
                    '路径遍历': [r"(\.\./)", r"(\.\.\\)"],
                    'XXE注入': [r"(<!ENTITY)", r"(<!DOCTYPE)"],
                }

                for attack_type, patterns in attack_patterns.items():
                    for pattern in patterns:
                        if re.search(pattern, payload_str, re.IGNORECASE):
                            suspicious_patterns.append({
                                'type': attack_type,
                                'pattern': pattern,
                                'payload': payload_str[:300]
                            })
                            break
            except:
                pass

    print("=" * 60)
    print("基础流量统计")
    print("=" * 60)
    print(f"\n协议分布:")
    for proto, count in sorted(protocols.items(), key=lambda x: x[1], reverse=True):
        print(f"  {proto}: {count}")

    print(f"\n目标端口 TOP 5:")
    for port, count in sorted(dst_ports.items(), key=lambda x: x[1], reverse=True)[:5]:
        print(f"  端口 {port}: {count} 次")

    print(f"\n源 IP TOP 5:")
    for ip, count in sorted(src_ips.items(), key=lambda x: x[1], reverse=True)[:5]:
        print(f"  {ip}: {count} 次")

    print(f"\n目标 IP TOP 5:")
    for ip, count in sorted(dst_ips.items(), key=lambda x: x[1], reverse=True)[:5]:
        print(f"  {ip}: {count} 次")

    print(f"\n找到 {len(http_requests)} 个 HTTP 请求")
    print(f"发现 {len(suspicious_patterns)} 个可疑模式")

except ImportError:
    print("scapy 未安装，尝试手动解析...")
    print("需要安装: pip install scapy")
except Exception as e:
    print(f"错误: {e}")
    import traceback
    traceback.print_exc()

